value1 = GetSymbolFieldDate(_group[_i], "來自營運之現金流量", "Q");
value2 = 0;
value3 = 0;
end;
// STEP 2 同樣期別時，數值計算
if GetSymbolFieldDate(_group[_i], "來自營運之現金流量", "Q") = value1 then begin //依最新的資料期別進行統計
value2 = value2 + 1;
value3 = value3 + GetSymbolField(_group[_i], "來自營運之現金流量", "Q");
end;
// 實際要計算的內容===結束===
end; 
end;
// 要繪製的指標
// 
